import { render, screen, fireEvent } from "@testing-library/react"
import { describe, it, expect, vi } from "vitest"
import { ConditionGuide } from "../ConditionGuide"

describe("ConditionGuide", () => {
  it("renders all 5 condition options", () => {
    const onChange = vi.fn()
    render(<ConditionGuide value="NM" onChange={onChange} />)

    expect(screen.getByText("Near Mint")).toBeInTheDocument()
    expect(screen.getByText("Lightly Played")).toBeInTheDocument()
    expect(screen.getByText("Moderately Played")).toBeInTheDocument()
    expect(screen.getByText("Heavily Played")).toBeInTheDocument()
    expect(screen.getByText("Damaged")).toBeInTheDocument()
  })

  it("highlights the selected condition", () => {
    const onChange = vi.fn()
    render(<ConditionGuide value="LP" onChange={onChange} />)

    const lpButton = screen.getByText("Lightly Played").closest("button")
    expect(lpButton?.style.boxShadow).toContain("0 0 0 2px")
  })

  it("calls onChange when a condition is clicked", () => {
    const onChange = vi.fn()
    render(<ConditionGuide value="NM" onChange={onChange} />)

    const hpButton = screen.getByText("Heavily Played").closest("button")!
    fireEvent.click(hpButton)

    expect(onChange).toHaveBeenCalledWith("HP")
  })

  it("renders in compact mode with condition codes only", () => {
    const onChange = vi.fn()
    render(<ConditionGuide value="NM" onChange={onChange} compact />)

    expect(screen.getByText("NM")).toBeInTheDocument()
    expect(screen.getByText("LP")).toBeInTheDocument()
    expect(screen.getByText("MP")).toBeInTheDocument()
    expect(screen.getByText("HP")).toBeInTheDocument()
    expect(screen.getByText("DMG")).toBeInTheDocument()
    expect(screen.queryByText("Near Mint")).not.toBeInTheDocument()
  })

  it("renders condition descriptions in full mode", () => {
    const onChange = vi.fn()
    render(<ConditionGuide value="NM" onChange={onChange} />)

    expect(screen.getByText(/minimal to no wear/)).toBeInTheDocument()
    expect(screen.getByText(/Major damage present/)).toBeInTheDocument()
  })
})

import { render, screen, fireEvent, waitFor, act } from "@testing-library/react"
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest"
import { ListingWizard } from "../wizard/ListingWizard"
import { WizardProgress } from "../wizard/WizardProgress"
import { CardSearchInput } from "../wizard/CardSearchInput"
import { PrintingGrid } from "../wizard/PrintingGrid"
import { WizardStepIdentify } from "../wizard/WizardStepIdentify"
import { WizardStepCondition } from "../wizard/WizardStepCondition"
import { WizardStepPrice } from "../wizard/WizardStepPrice"
import { ConditionGradeSelector } from "../wizard/ConditionGradeSelector"
import { PhotoUploader } from "../wizard/PhotoUploader"
import { MarketPriceDisplay } from "../wizard/MarketPriceDisplay"
import { CompetitiveGauge } from "../wizard/CompetitiveGauge"
import { ShippingSelector } from "../wizard/ShippingSelector"
import { ConfirmationSummary } from "../wizard/ConfirmationSummary"
import type { CardSearchResult, PrintOption } from "../wizard/CardSearchInput"

// --- Router mock ---

const mockPush = vi.fn()
vi.mock("next/navigation", () => ({
  useRouter: () => ({ push: mockPush }),
}))

// --- Server action mocks ---

const mockCreateSellerListing = vi.fn()
const mockUploadListingImage = vi.fn()

vi.mock("@/lib/data/seller-dashboard", () => ({
  createSellerListing: (...args: unknown[]) => mockCreateSellerListing(...args),
  uploadListingImage: (...args: unknown[]) => mockUploadListingImage(...args),
}))

// --- Mocks ---

const mockCard: CardSearchResult = {
  id: "card-1",
  name: "Ragavan, Nimble Pilferer",
  setName: "Modern Horizons 2",
  rarity: "Mythic Rare",
  prints: [
    {
      id: "print-1",
      setName: "Modern Horizons 2",
      setCode: "MH2",
      collectorNumber: "138",
    },
    {
      id: "print-2",
      setName: "MH2 (Extended Art)",
      setCode: "MH2",
      collectorNumber: "382",
    },
  ],
}

const mockPrint: PrintOption = mockCard.prints[0]

function mockFetchSuccess(data: unknown) {
  return vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve(data),
  })
}

function mockFetchError(status = 500) {
  return vi.fn().mockResolvedValue({
    ok: false,
    status,
    json: () => Promise.resolve({ error: "Server error" }),
  })
}

// --- WizardProgress ---

describe("WizardProgress", () => {
