// --- PhotoUploader ---

describe("PhotoUploader", () => {
  it("renders two upload zones", () => {
    render(
      <PhotoUploader photos={[]} onPhotosChange={vi.fn()} uploadImage={vi.fn()} />
    )

    expect(screen.getByTestId("photo-uploader")).toBeInTheDocument()
    expect(screen.getByTestId("photo-zone-0")).toBeInTheDocument()
    expect(screen.getByTestId("photo-zone-1")).toBeInTheDocument()
    expect(screen.getByText("Front of Card")).toBeInTheDocument()
    expect(screen.getByText("Back of Card")).toBeInTheDocument()
  })

  it("has hidden file inputs", () => {
    render(
      <PhotoUploader photos={[]} onPhotosChange={vi.fn()} uploadImage={vi.fn()} />
    )

    const input0 = screen.getByTestId("photo-input-0")
    const input1 = screen.getByTestId("photo-input-1")
    expect(input0).toHaveAttribute("type", "file")
    expect(input0).toHaveAttribute("accept", "image/*")
    expect(input1).toHaveAttribute("type", "file")
  })

  it("shows preview when photo URL is provided", () => {
    render(
      <PhotoUploader
        photos={["https://example.com/front.jpg"]}
        onPhotosChange={vi.fn()}
        uploadImage={vi.fn()}
      />
    )

    // Zone 0 should have an image
    const zone0 = screen.getByTestId("photo-zone-0")
    const img = zone0.querySelector("img")
    expect(img).toBeTruthy()
    expect(img?.getAttribute("src")).toBe("https://example.com/front.jpg")
  })

  it("calls uploadImage on file select and updates photos", async () => {
    const uploadImage = vi.fn().mockResolvedValue("https://uploaded.com/img.jpg")
    const onPhotosChange = vi.fn()

    render(
      <PhotoUploader
        photos={[]}
        onPhotosChange={onPhotosChange}
        uploadImage={uploadImage}
      />
    )

    const input = screen.getByTestId("photo-input-0")
    const file = new File(["test"], "test.jpg", { type: "image/jpeg" })

    await act(async () => {
      fireEvent.change(input, { target: { files: [file] } })
    })

    await waitFor(() => {
      expect(uploadImage).toHaveBeenCalledWith(file)
    })

    await waitFor(() => {
      expect(onPhotosChange).toHaveBeenCalledWith(["https://uploaded.com/img.jpg"])
    })
  })
})

