describe("WizardStepCondition", () => {
  const defaultProps = {
    condition: "NM" as const,
    photos: [],
    description: "",
    onConditionChange: vi.fn(),
    onPhotosChange: vi.fn(),
    onDescriptionChange: vi.fn(),
