describe("MarketPriceDisplay", () => {
  afterEach(() => {
    vi.restoreAllMocks()
  })

  it("renders loading then market prices", async () => {
    global.fetch = mockFetchSuccess({ low: 5200, median: 5899, high: 6850 })

